import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const ModeratorDashboard = () => {
  const [users, setUsers] = useState([]);
  const [error, setError] = useState('');
  const [editUserId, setEditUserId] = useState(null);
  const [editFormData, setEditFormData] = useState({
    email: '',
    role: '',
  });
  const navigate = useNavigate();
  const token = localStorage.getItem('accessToken');

  useEffect(() => {
    if (!token) {
      setError('No token found. Please log in again.');
      navigate('/login');
      return;
    }

    fetch('http://localhost:8000/api/manage-users/', {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data)) {
          setUsers(data);
        } else {
          setError('Invalid response format');
          console.log('API response:', data);
        }
      })
      .catch((err) => {
        console.error(err);
        setError('Failed to load users.');
      });
  }, []);

  const deleteUser = (id) => {
    fetch(`http://localhost:8000/api/manage-users/${id}/`, {
      method: 'DELETE',
      headers: {
        Authorization: `Bearer ${token}`,
      },
    }).then(() => {
      setUsers(users.filter((user) => user.id !== id));
    });
  };

  const handleEditClick = (user) => {
    setEditUserId(user.id);
    setEditFormData({
      email: user.email || '',
      role: user.role,
    });
  };

  const handleEditChange = (e) => {
    setEditFormData({ ...editFormData, [e.target.name]: e.target.value });
  };

  const handleEditSubmit = (e) => {
    e.preventDefault();
    fetch(`http://localhost:8000/api/manage-users/${editUserId}/`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify(editFormData),
    })
      .then((res) => res.json())
      .then((updatedUser) => {
        setUsers(users.map((u) => (u.id === editUserId ? updatedUser : u)));
        setEditUserId(null);
      });
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Moderator Dashboard</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <table border="1" cellPadding="8" style={{ width: '100%' }}>
        <thead>
          <tr>
            <th>ID</th>
            <th>Username</th>
            <th>Role</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u.id}>
              <td>{u.id}</td>
              <td>{u.username}</td>
              <td>{u.role}</td>
              <td>
                <button onClick={() => deleteUser(u.id)}>Delete</button>
                <button onClick={() => handleEditClick(u)}>Edit</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {editUserId && (
        <form onSubmit={handleEditSubmit} style={{ marginTop: '2rem' }}>
          <h4>Edit User</h4>
          <input
            type="email"
            name="email"
            value={editFormData.email}
            onChange={handleEditChange}
            placeholder="Email"
            required
          />
          <select
            name="role"
            value={editFormData.role}
            onChange={handleEditChange}
            required
          >
            <option value="student">Student</option>
            <option value="teacher">Teacher</option>
            <option value="moderator">Moderator</option>
          </select>
          <button type="submit">Save</button>
          <button type="button" onClick={() => setEditUserId(null)}>
            Cancel
          </button>
        </form>
      )}
    </div>
  );
};

export default ModeratorDashboard;
